353	  template <class ProblemShape>
354	  static constexpr Params
355	  to_underlying_arguments(
356	    ProblemShape const& problem_shape,
357	    Arguments const& args,
358	    [[maybe_unused]] void* workspace,
359	    cutlass::KernelHardwareInfo const& hw_info = cutlass::KernelHardwareInfo{}) {
360	
361	    // Optionally append 1s until problem shape is rank-4 (MNKL), in case it is only rank-3 (MNK)
362	    auto problem_shape_MNKL = append<4>(problem_shape, 1);
363	    auto [M,N,K,L] = problem_shape_MNKL;
364	
365	    auto ptr_A = recast_ptr<TmaInternalElementA>(args.ptr_A);
366	    auto ptr_B = recast_ptr<TmaInternalElementB>(args.ptr_B);
367	
368	    Tensor tensor_a = make_tensor(ptr_A, make_layout(make_shape(M,K,L), args.dA));
369	    Tensor tensor_b = make_tensor(ptr_B, make_layout(make_shape(N,K,L), args.dB));
370	
371	    auto cluster_shape = cutlass::detail::select_cluster_shape(ClusterShape{}, hw_info.cluster_shape);
372	
373	    // Cluster layout for TMA construction
374	    auto cluster_layout_vmnk = tiled_divide(make_layout(cluster_shape), make_tile(typename TiledMma::AtomThrID{}));
375	    auto cluster_shape_fallback = cutlass::detail::select_cluster_shape(ClusterShape{}, hw_info.cluster_shape_fallback);
376	    auto cluster_layout_vmnk_fallback = tiled_divide(make_layout(cluster_shape_fallback), make_tile(typename TiledMma::AtomThrID{}));
377	    typename Params::TMA_A tma_load_a = make_tma_atom_A_sm100<TmaInternalElementA>(
378	        GmemTiledCopyA{},
379	        tensor_a,
380	        SmemLayoutA{}(_,_,_,cute::Int<0>{}),
381	        TileShape{},
382	        TiledMma{},
383	        cluster_layout_vmnk);
384	
385	    typename Params::TMA_B tma_load_b = make_tma_atom_B_sm100<TmaInternalElementB>(
386	        GmemTiledCopyB{},
387	        tensor_b,
388	        SmemLayoutB{}(_,_,_,cute::Int<0>{}),
389	        TileShape{},
390	        TiledMma{},
391	        cluster_layout_vmnk);
392	
393	    typename Params::TMA_A tma_load_a_fallback = make_tma_atom_A_sm100<TmaInternalElementA>(
394	        GmemTiledCopyA{},
395	        tensor_a,
396	        SmemLayoutA{}(_,_,_,cute::Int<0>{}),
397	        TileShape{},
398	        TiledMma{},
399	        cluster_layout_vmnk_fallback);
400	
401	    typename Params::TMA_B tma_load_b_fallback = make_tma_atom_B_sm100<TmaInternalElementB>(
402	        GmemTiledCopyB{},
403	        tensor_b,
404	        SmemLayoutB{}(_,_,_,cute::Int<0>{}),
405	        TileShape{},
406	        TiledMma{},
407	        cluster_layout_vmnk_fallback);
408	
409	    return {
410	      tma_load_a,
411	      tma_load_b,
412	      tma_load_a_fallback,
413	      tma_load_b_fallback,
414	      hw_info.cluster_shape_fallback,
415	      args.runtime_data_type_a,
416	      args.runtime_data_type_b
417	    };
418	  }
