420	  template <class ProblemShape>
421	  static bool
422	  can_implement(
423	      ProblemShape const& problem_shape,
424	      [[maybe_unused]] Arguments const& args) {
425	
426	    auto problem_shape_MNKL = append<4>(problem_shape, 1);
427	    auto [M,N,K,L] = problem_shape_MNKL;
428	
429	    static constexpr bool IsF8F6F4 = detail::is_sm100_mma_f8f6f4<TiledMma, ElementA, ElementB>();
430	    constexpr int tma_alignment_bits_A = cutlass::detail::get_input_alignment_bits<ElementA, IsF8F6F4>();
431	    constexpr int tma_alignment_bits_B = cutlass::detail::get_input_alignment_bits<ElementB, IsF8F6F4>();
432	    constexpr int min_tma_aligned_elements_A = tma_alignment_bits_A / cute::sizeof_bits<ElementA>::value;
433	
434	    bool implementable = true;
435	    implementable = implementable && cutlass::detail::check_alignment<min_tma_aligned_elements_A>(cute::make_shape(M,K,L), StrideA{});
436	    constexpr int min_tma_aligned_elements_B = tma_alignment_bits_B / cute::sizeof_bits<ElementB>::value;
437	    implementable = implementable && cutlass::detail::check_alignment<min_tma_aligned_elements_B>(cute::make_shape(N,K,L), StrideB{});
438	
439	    if (!implementable) {
440	      CUTLASS_TRACE_HOST("  CAN IMPLEMENT: Problem Size doesn't meet the minimum alignment requirements for TMA.\n");
441	    }
442	    return implementable;
443	  }
