489	  /// Set up the data needed by this collective for load.
490	  /// Return tuple element contain
491	  /// gA_mkl - The tiled tma tensor for input A
492	  /// gB_nkl - The tiled tma tensor for input B
493	  /// tAsA - partitioned smem tensor for A
494	  /// tBsB - partitioned smem tensor for B
495	  /// mcast_mask_a - tma multicast mask for A
496	  /// mcast_mask_b - tma multicast mask for B
497	  template <class ProblemShape_MNKL>
498	  CUTLASS_DEVICE auto
499	  load_init(
500	      ProblemShape_MNKL const& problem_shape_MNKL,
501	      TensorStorage& shared_tensors) const {
502	    using X = Underscore;
503	
504	    // Separate out problem shape for convenience
505	    auto [M,N,K,L] = problem_shape_MNKL;
506	
507	    // Represent the full tensors -- get these from TMA
508	    Tensor mA_mkl = observed_tma_load_a_->get_tma_tensor(make_shape(M,K,L));
509	    Tensor mB_nkl = observed_tma_load_b_->get_tma_tensor(make_shape(N,K,L));
510	
511	    // Tile the tensors and defer the slice
512	    Tensor gA_mkl = local_tile(mA_mkl, TileShape{}, make_coord(_,_,_), Step<_1, X,_1>{});    // (BLK_M, BLK_K, m, k, l)
513	    Tensor gB_nkl = local_tile(mB_nkl, TileShape{}, make_coord(_,_,_), Step< X,_1,_1>{});    // (BLK_N, BLK_K, n, k, l)
514	
515	    // Partition for this CTA
516	    ThrMMA cta_mma = TiledMma{}.get_slice(blockIdx.x % size(typename TiledMma::AtomThrID{}));
517	
518	    Tensor tCgA_mkl = cta_mma.partition_A(gA_mkl);          // (MMA, MMA_M, MMA_K, m, k, l)
519	    Tensor tCgB_nkl = cta_mma.partition_B(gB_nkl);          // (MMA, MMA_N, MMA_K, n, k, l)
520	
521	    Tensor sA = make_tensor(make_smem_ptr(shared_tensors.smem_A.begin()), SmemLayoutA{});  // (MMA,MMA_M,MMA_K,PIPE)
522	    Tensor sB = make_tensor(make_smem_ptr(shared_tensors.smem_B.begin()), SmemLayoutB{});  // (MMA,MMA_N,MMA_K,PIPE)
523	
524	    // Define the CTA-in-cluster Layout and Coord
525	    Layout cta_layout_mnk  = make_layout(cluster_shape_);
526	    Layout cta_layout_vmnk = tiled_divide(cta_layout_mnk, make_tile(typename TiledMma::AtomThrID{}));
527	    auto cta_coord_vmnk  = cta_layout_vmnk.get_flat_coord(block_rank_in_cluster_);
528	
529	    // Project the cta_layout for tma_a along the n-modes
530	    auto [tAgA_mkl, tAsA] = tma_partition(*observed_tma_load_a_,
531	                                      get<2>(cta_coord_vmnk), make_layout(size<2>(cta_layout_vmnk)),
532	                                      group_modes<0,3>(sA), group_modes<0,3>(tCgA_mkl));
533	
534	    // Project the cta_layout for tma_b along the m-modes
535	    auto [tBgB_nkl, tBsB] = tma_partition(*observed_tma_load_b_,
536	                                      get<1>(cta_coord_vmnk), make_layout(size<1>(cta_layout_vmnk)),
537	                                      group_modes<0,3>(sB), group_modes<0,3>(tCgB_nkl));
538	
539	    // TMA Multicast Masks
540	    uint16_t mcast_mask_a = create_tma_multicast_mask<2>(cta_layout_vmnk, cta_coord_vmnk);
541	    uint16_t mcast_mask_b = create_tma_multicast_mask<1>(cta_layout_vmnk, cta_coord_vmnk);
542	
543	    return LoadParams{
544	      shape<3>(gA_mkl),                       // for scheduler
545	      tAgA_mkl, tBgB_nkl, tAsA, tBsB,        // for input tensor values
546	      mcast_mask_a, mcast_mask_b};           // multicast masks
547	  }
548	
549	  /// Set up the data needed by this collective for mma compute.
550	  template <class TmemStorage>
551	  CUTLASS_DEVICE auto
552	  mma_init(
553	    [[maybe_unused]] TmemStorage tmem_storage,
554	    TensorStorage& shared_tensors) const {
555	
556	    // Allocate "fragments/descriptors" for A and B matrices
557	    Tensor sA = make_tensor(make_smem_ptr(shared_tensors.smem_A.begin()), SmemLayoutA{});          // (BLK_M,BLK_K,PIPE)
558	    Tensor sB = make_tensor(make_smem_ptr(shared_tensors.smem_B.begin()), SmemLayoutB{});          // (BLK_N,BLK_K,PIPE)
559	
560	    // Allocate "fragments/descriptors" for A and B matrices
561	    Tensor tCrA = TiledMma::make_fragment_A(sA);                                           // (MMA,MMA_M,MMA_K,PIPE)
562	    Tensor tCrB = TiledMma::make_fragment_B(sB);                                           // (MMA,MMA_N,MMA_K,PIPE)
563	
564	    CUTE_STATIC_ASSERT_V(Int<DispatchPolicy::Stages>{} == size<3>(sA));                                     // PIPE
565	    CUTE_STATIC_ASSERT_V(Int<DispatchPolicy::Stages>{} == size<3>(sB));                                     // PIPE
566	
567	    TiledMma tiled_mma;
568	
569	    if constexpr (IsRuntimeDataType) {
570	      // Update instruction descriptor according to runtime argument.
571	      // Applying bitmask (0b111) to help compiler deduce that the conversion and assignment are safe.
572	      tiled_mma.idesc_.a_format_ = uint8_t(runtime_data_type_a_) & 0b111;
573	      tiled_mma.idesc_.b_format_ = uint8_t(runtime_data_type_b_) & 0b111;
574	    }
575	
576	    return MmaParams{
577	      tiled_mma,
578	      tCrA, tCrB};
579	  }
580	
581	  /// Perform a collective-scoped matrix multiply-accumulate
582	  /// Producer Perspective
583	  template <
584	    class LoadParams,
585	    class TileCoordMNKL,
586	    class KTileIterator
587	  >
588	  CUTLASS_DEVICE auto
589	  load(
590	    MainloopPipeline mainloop_pipeline,
591	    MainloopPipelineState mainloop_pipe_producer_state,
592	    LoadParams const& load_inputs,
593	    TileCoordMNKL const& cta_coord_mnkl,
594	    KTileIterator k_tile_iter, int k_tile_count) {
595	
596	    auto [unused_k_tiles,
597	          tAgA_mkl, tBgB_nkl, tAsA, tBsB,
598	          mcast_mask_a, mcast_mask_b] = load_inputs;
599	
600	    // slice out the work coord from partitioned tensors
601	    Tensor tAgA = tAgA_mkl(_, get<0>(cta_coord_mnkl) / size(typename TiledMma::AtomThrID{}), _, get<3>(cta_coord_mnkl));
602	    Tensor tBgB = tBgB_nkl(_, get<1>(cta_coord_mnkl), _, get<3>(cta_coord_mnkl));
603	
604	    auto barrier_token = mainloop_pipeline.producer_try_acquire(mainloop_pipe_producer_state);
605	
606	    // Issue the Mainloop loads
607	    CUTLASS_PRAGMA_NO_UNROLL
608	    while (k_tile_count > 0) {
609	      // LOCK mainloop_pipe_producer_state for _writing_
610	      mainloop_pipeline.producer_acquire(mainloop_pipe_producer_state, barrier_token);
611	
612	      using BarrierType = typename MainloopPipeline::ProducerBarrierType;
613	      BarrierType* tma_barrier = mainloop_pipeline.producer_get_barrier(mainloop_pipe_producer_state);
614	
615	      int write_stage = mainloop_pipe_producer_state.index();
616	      ++mainloop_pipe_producer_state;
617	      barrier_token = mainloop_pipeline.producer_try_acquire(mainloop_pipe_producer_state);
618	
619	      if (cute::elect_one_sync()) {
620	        copy(observed_tma_load_a_->with(*tma_barrier, mcast_mask_a), tAgA(_,*k_tile_iter), tAsA(_,write_stage));
621	        copy(observed_tma_load_b_->with(*tma_barrier, mcast_mask_b), tBgB(_,*k_tile_iter), tBsB(_,write_stage));
622	      }
623	
624	      --k_tile_count;
625	      ++k_tile_iter;
626	    }
627	
628	    return cute::make_tuple(mainloop_pipe_producer_state, k_tile_iter);
629	  }
630	
631	  /// Perform a Producer Epilogue to prevent early exit of ctas in a Cluster
632	  CUTLASS_DEVICE void
633	  load_tail(MainloopPipeline mainloop_pipeline, MainloopPipelineState mainloop_pipe_producer_state) {
634	    // Issue the epilogue waits
635	    // This helps avoid early exit of ctas in Cluster
636	    // Waits for all stages to either be released (all
637	    // Consumer UNLOCKs), or if the stage was never used
638	    // then would just be acquired since the phase was
639	    // still inverted from make_producer_start_state
640	    mainloop_pipeline.producer_tail(mainloop_pipe_producer_state);
641	  }
642	
643	  /// Perform a collective-scoped matrix multiply-accumulate
644	  /// Consumer Perspective
645	  template <
646	    class AccumulatorPipeline,
647	    class FrgEngine, class FrgLayout,
648	    class MmaParams,
649	    class CtaTileCoord
650	  >
651	  CUTLASS_DEVICE auto
652	  mma(cute::tuple<MainloopPipeline,
653	                  AccumulatorPipeline> pipelines,
654	      cute::tuple<MainloopPipelineState,
655	                  typename AccumulatorPipeline::PipelineState> pipeline_states,
656	      cute::tuple<cute::Tensor<FrgEngine, FrgLayout>> const& accumulators_pair,
657	      MmaParams const& mma_inputs,
658	      CtaTileCoord cta_tile_coord,
659	      int k_tile_count
660	  ) {
661	    static_assert(is_tmem<FrgEngine>::value, "Accumulator must be tmem resident.");
662	    static_assert(rank(FrgLayout{}) == 3, "Accumulator must be MMA-partitioned: (MMA, MMA_M, MMA_N)");
663	
664	    auto accumulators = get<0>(accumulators_pair);
665	    auto [tiled_mma, tCrA, tCrB] = mma_inputs;
666	
667	    auto [mainloop_pipeline, accumulator_pipeline] = pipelines;
668	    auto [mainloop_pipe_consumer_state, accumulator_pipe_producer_state] = pipeline_states;
669	
670	    uint32_t skip_wait = k_tile_count <= 0;
671	    auto barrier_token = mainloop_pipeline.consumer_try_wait(mainloop_pipe_consumer_state, skip_wait);
672	
673	    //
674	    // PIPELINED MAIN LOOP
675	    //
676	    tiled_mma.accumulate_ = UMMA::ScaleOut::Zero;
677	    // Wait for tmem accumulator buffer to become empty with a flipped phase
678	    accumulator_pipeline.producer_acquire(accumulator_pipe_producer_state);
679	
680	    CUTLASS_PRAGMA_NO_UNROLL
681	    while (k_tile_count > 0) {
682	      // WAIT on mainloop_pipe_consumer_state until its data are available
683	      // (phase bit flips from mainloop_pipe_consumer_state.phase() value)
684	      mainloop_pipeline.consumer_wait(mainloop_pipe_consumer_state, barrier_token);
685	
686	      // Compute on k_tile
687	      int read_stage = mainloop_pipe_consumer_state.index();
688	      // Save current mainlop pipeline read state
689	      auto curr_mainloop_pipe_consumer_state = mainloop_pipe_consumer_state;
690	
691	      // Advance mainloop_pipe
692	      ++mainloop_pipe_consumer_state;
693	      --k_tile_count;
694	      skip_wait = k_tile_count <= 0;
695	      // Peek at next iteration
696	      barrier_token = mainloop_pipeline.consumer_try_wait(mainloop_pipe_consumer_state, skip_wait);
697	
698	      // Unroll the K mode manually so we can set scale C to 1
699	      CUTLASS_PRAGMA_UNROLL
700	      for (int k_block = 0; k_block < size<2>(tCrA); ++k_block) {
701	        // (V,M) x (V,N) => (V,M,N)
702	        cute::gemm(tiled_mma,
703	                   tCrA(_,_,k_block,read_stage),
704	                   tCrB(_,_,k_block,read_stage),
705	                   accumulators);
706	        tiled_mma.accumulate_ = UMMA::ScaleOut::One;
707	      }
708	      mainloop_pipeline.consumer_release(curr_mainloop_pipe_consumer_state);
709	    }
710	
711	    return mainloop_pipe_consumer_state;
712	  }
713	
714	protected:
715	
716	  typename Params::TMA_A const* observed_tma_load_a_{nullptr};
717	  typename Params::TMA_B const* observed_tma_load_b_{nullptr};
718	  RuntimeDataTypeA runtime_data_type_a_{};
719	  RuntimeDataTypeB runtime_data_type_b_{};
720	
721	  ClusterShape cluster_shape_;
722	  uint32_t block_rank_in_cluster_;
723	};
724	
725	/////////////////////////////////////////////////////////////////////////////////////////////////
726	
727	} // namespace cutlass::gemm::collective
728	
729	/////////////////////////////////////////////////////////////////////////////////////////////////
