243	    uint32_t mma       = false;
244	    uint32_t sched     = false;
245	    uint32_t main_load = false;
246	    uint32_t epi_load  = false;
247	    uint32_t epilogue  = false;
248	  };
249	
250	  //
251	  // Methods
252	  //
253	
254	  // Convert to underlying arguments.
255	  static
256	  Params
257	  to_underlying_arguments(Arguments const& args, void* workspace) {
258	    (void) workspace;
259	    auto problem_shape = args.problem_shape;
260	    auto problem_shape_MNKL = append<4>(problem_shape, 1);
261	
262	    // Get SM count if needed, otherwise use user supplied SM count
263	    int sm_count = args.hw_info.sm_count;
264	    if (sm_count != 0) {
265	      CUTLASS_TRACE_HOST("  WARNING: SM100 tile scheduler does not allow for user specified SM counts.\n"
266	          "  To restrict a kernel's resource usage, consider using CUDA driver APIs instead (green contexts).");
267	    }
268	    CUTLASS_TRACE_HOST("to_underlying_arguments(): Setting persistent grid SM count to " << sm_count);
269	
270	    // Calculate workspace pointers
271	    uint8_t* workspace_ptr = reinterpret_cast<uint8_t*>(workspace);
272	    size_t workspace_offset = 0;
273	
274	    // Epilogue
275	    void* epilogue_workspace = workspace_ptr + workspace_offset;
276	    workspace_offset += CollectiveEpilogue::get_workspace_size(args.problem_shape, args.epilogue);
277	    workspace_offset = round_nearest(workspace_offset,  MinWorkspaceAlignment);
278	
279	    void* mainloop_workspace = nullptr;
280	
281	    // Tile scheduler
282	    void* scheduler_workspace = workspace_ptr + workspace_offset;
283	    workspace_offset += TileScheduler::template get_workspace_size<ProblemShape, ElementAccumulator>(
284	      args.scheduler, args.problem_shape, args.hw_info, NumFixupBarriers, NumEpilogueSubTiles, CollectiveEpilogue::NumAccumulatorMtxs);
285	    workspace_offset = round_nearest(workspace_offset,  MinWorkspaceAlignment);
286	
287	    return {
288	      args.mode,
289	      args.problem_shape,
290	      CollectiveMainloop::to_underlying_arguments(args.problem_shape, args.mainloop, mainloop_workspace, args.hw_info),
291	      CollectiveEpilogue::to_underlying_arguments(args.problem_shape, args.epilogue, epilogue_workspace),
292	      TileScheduler::to_underlying_arguments(
293	        problem_shape_MNKL, TileShape{}, AtomThrShapeMNK{}, ClusterShape{},
294	        args.hw_info, args.scheduler, scheduler_workspace
295	      )
296	      ,args.hw_info
297	    };
298	  }
299	
300	  static bool
301	  can_implement(Arguments const& args) {
302	    bool implementable = (args.mode == GemmUniversalMode::kGemm) or
303	        (args.mode == GemmUniversalMode::kBatched && rank(ProblemShape{}) == 4);
304	    if (!implementable) {
305	      CUTLASS_TRACE_HOST("  CAN IMPLEMENT: Arguments or Problem Shape don't meet the requirements.\n");
306	      return implementable;
307	    }
308	    implementable &= CollectiveMainloop::can_implement(args.problem_shape, args.mainloop);
309	    implementable &= CollectiveEpilogue::can_implement(args.problem_shape, args.epilogue);
310	    implementable &= TileScheduler::can_implement(args.scheduler, args.hw_info);
311	
312	    if constexpr (IsDynamicCluster) {
313	      static constexpr int MaxClusterSize = 16;
314	      implementable &= size(args.hw_info.cluster_shape) <= MaxClusterSize;
315	      implementable &= size(args.hw_info.cluster_shape_fallback) <= MaxClusterSize;
316	      implementable &= cutlass::detail::preferred_cluster_can_implement<AtomThrShapeMNK>(args.hw_info.cluster_shape, args.hw_info.cluster_shape_fallback);
317	    }
318	    
319	    constexpr bool IsBlockscaled = !cute::is_void_v<ElementSF>;
320	    if constexpr (IsBlockscaled) {
321	      if constexpr (IsDynamicCluster) {
322	        implementable &= cutlass::detail::preferred_cluster_can_implement<AtomThrShapeMNK>(args.hw_info.cluster_shape, args.hw_info.cluster_shape_fallback);
323	        // Special cluster shape check for scale factor multicasts. Due to limited size of scale factors, we can't multicast among
324	        // more than 4 CTAs
325	        implementable &= (args.hw_info.cluster_shape.x <= 4 && args.hw_info.cluster_shape.y <= 4 &&
326	                          args.hw_info.cluster_shape_fallback.x <= 4 && args.hw_info.cluster_shape_fallback.y <= 4);
327	      }
328	      else {
329	        // Special cluster shape check for scale factor multicasts. Due to limited size of scale factors, we can't multicast among
330	        // more than 4 CTAs
331	        implementable &= ((size<0>(ClusterShape{}) <= 4) && (size<1>(ClusterShape{}) <= 4));
332	      }
333	    }
334	
335	    return implementable;
336	  }
