338	  static size_t
339	  get_workspace_size(Arguments const& args) {
340	    size_t workspace_size = 0;
341	
342	    // Epilogue
343	    workspace_size += CollectiveEpilogue::get_workspace_size(args.problem_shape, args.epilogue);
344	    workspace_size = round_nearest(workspace_size,  MinWorkspaceAlignment);
345	
346	    // Tile scheduler
347	    workspace_size += TileScheduler::template get_workspace_size<ProblemShape, ElementAccumulator>(
348	      args.scheduler, args.problem_shape, args.hw_info, NumFixupBarriers, NumEpilogueSubTiles, CollectiveEpilogue::NumAccumulatorMtxs);
349	    workspace_size = round_nearest(workspace_size,  MinWorkspaceAlignment);
350	
351	    return workspace_size;
352	  }
353	
354	  static cutlass::Status
355	  initialize_workspace(Arguments const& args, void* workspace = nullptr, cudaStream_t stream = nullptr,
356	    CudaHostAdapter* cuda_adapter = nullptr) {
357	    Status status = Status::kSuccess;
358	    uint8_t* workspace_ptr = reinterpret_cast<uint8_t*>(workspace);
359	    size_t workspace_offset = 0;
360	
361	    // Epilogue
362	    status = CollectiveEpilogue::initialize_workspace(args.problem_shape, args.epilogue, workspace_ptr + workspace_offset, stream, cuda_adapter);
363	    workspace_offset += CollectiveEpilogue::get_workspace_size(args.problem_shape, args.epilogue);
364	    workspace_offset = round_nearest(workspace_offset,  MinWorkspaceAlignment);
365	    if (status != Status::kSuccess) {
366	      return status;
367	    }
368	
369	    // Tile scheduler
370	    status = TileScheduler::template initialize_workspace<ProblemShape, ElementAccumulator>(
371	      args.scheduler, workspace_ptr + workspace_offset, stream, args.problem_shape, args.hw_info, NumFixupBarriers, NumEpilogueSubTiles, CollectiveEpilogue::NumAccumulatorMtxs, cuda_adapter);
372	    workspace_offset += TileScheduler::template get_workspace_size<ProblemShape, ElementAccumulator>(
373	      args.scheduler, args.problem_shape, args.hw_info, NumFixupBarriers, NumEpilogueSubTiles, CollectiveEpilogue::NumAccumulatorMtxs);
374	    workspace_offset = round_nearest(workspace_offset,  MinWorkspaceAlignment);
375	    if (status != Status::kSuccess) {
376	      return status;
377	    }
378	
379	    return status;
380	  }
