385	    // NOTE cluster_shape here is the major cluster shape, not fallback one
386	    auto cluster_shape = cutlass::detail::select_cluster_shape(ClusterShape{}, params.hw_info.cluster_shape);
387	
388	    auto problem_shape_MNKL = append<4>(params.problem_shape, Int<1>{});
389	    return TileScheduler::get_grid_shape(
390	        params.scheduler,
391	        problem_shape_MNKL,
